class ThemeEngine{constructor(){this.currentTheme=null;this.transitionDuration=800;this.initialized=false}init(initialPage="home"){if(this.initialized)return;this.ensureRootVariables();this.switchTheme(initialPage,false);this.setupAutoThemeDetection();this.initialized=true;console.log("✨ Theme Engine initialized")}ensureRootVariables(){const root=document.documentElement;const defaultVars={"--theme-transition-duration":"800ms","--theme-transition-timing":"cubic-bezier(0.4, 0, 0.2, 1)","--glassmorphism-blur":"10px","--glow-strength":"1","--accent-saturation":"100%"};Object.entries(defaultVars).forEach(([key,value])=>{if(!getComputedStyle(root).getPropertyValue(key)){root.style.setProperty(key,value)}})}switchTheme(pageName,animate=true){if(!window.THEMES_CONFIG){console.warn("⚠️ THEMES_CONFIG not found. Make sure themes-config.js is loaded.");return}const theme=THEMES_CONFIG[pageName.toLowerCase()]||THEMES_CONFIG.home;if(animate){this.transitionTheme(theme,pageName)}else{this.applyTheme(theme,pageName)}}applyTheme(theme,pageName){const root=document.documentElement;root.style.setProperty("--theme-bg",theme.colors.base.background);root.style.setProperty("--theme-bg-secondary",theme.colors.base.secondary);root.style.setProperty("--theme-text",theme.colors.base.text);root.style.setProperty("--theme-text-secondary",theme.colors.base.textSecondary);root.style.setProperty("--theme-accent-primary",theme.colors.accents.primary);root.style.setProperty("--theme-accent-secondary",theme.colors.accents.secondary);root.style.setProperty("--theme-accent-tertiary",theme.colors.accents.tertiary);root.style.setProperty("--theme-gold",theme.colors.accents.gold);Object.entries(theme.colors.gradients).forEach(([key,gradient],index)=>{root.style.setProperty(`--theme-gradient-${index+1}`,gradient)});this.currentTheme=theme;this.currentPageName=pageName;window.dispatchEvent(new CustomEvent("themeChanged",{detail:{theme:theme,pageName:pageName}}));console.log(`🎨 Theme applied: ${pageName}`)}transitionTheme(theme,pageName){const root=document.documentElement;document.body.classList.add("theme-transitioning");gsap.timeline().to(document.body,{opacity:.8,duration:this.transitionDuration/1e3*.5,ease:"power2.inOut"},0).call(()=>{this.applyTheme(theme,pageName)},null,this.transitionDuration/1e3*.5).to(document.body,{opacity:1,duration:this.transitionDuration/1e3*.5,ease:"power2.inOut"},this.transitionDuration/1e3*.5).call(()=>{document.body.classList.remove("theme-transitioning")})}detectCurrentPage(){const path=window.location.pathname;const filename=path.split("/").pop()||"index.html";let pageName="home";if(filename.includes("journey"))pageName="journey";else if(filename.includes("creations"))pageName="creations";else if(filename.includes("odyssey"))pageName="odyssey";else if(filename.includes("connect"))pageName="connect";return pageName}setupAutoThemeDetection(){const currentPage=this.detectCurrentPage();this.applyTheme(THEMES_CONFIG[currentPage],currentPage);window.addEventListener("popstate",()=>{const newPage=this.detectCurrentPage();this.switchTheme(newPage)})}getCurrentTheme(){return this.currentTheme}getCurrentPageName(){return this.currentPageName}setTransitionDuration(duration){this.transitionDuration=duration;document.documentElement.style.setProperty("--theme-transition-duration",`${duration}ms`)}setAccentSaturation(saturation){document.documentElement.style.setProperty("--accent-saturation",`${saturation}%`)}setGlowStrength(strength){document.documentElement.style.setProperty("--glow-strength",strength)}}const themeEngine=new ThemeEngine;if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{if(window.THEMES_CONFIG){themeEngine.init()}})}else{if(window.THEMES_CONFIG){themeEngine.init()}}if(typeof module!=="undefined"&&module.exports){module.exports=ThemeEngine}